module RefModule(
    input clk,
    input rst,
    input [15:0] in_data,
    output [15:0] out_data
);reg [15:0] out_data_reg;

always @(posedge clk) begin
    if (rst) begin
        out_data_reg <= 0;
    end else begin
        out_data_reg <= ~in_data;
    end
end

wire __out_data_tmp = out_data_reg;
assign out_data = __out_data_tmp;

endmodule
